// ============================================================================
// JSON Parsing Utilities (simple, header-only)
// ============================================================================

namespace json_util {

// Simple JSON array parser for numeric data
// Assumes well-formed JSON from our Python generator
class ArrayData {
public:
    std::vector<int64_t> shape;
    std::string dtype;
    std::vector<double> data;

    bool load(const std::string& filepath) {
        std::ifstream file(filepath);
        if (!file.is_open()) {
            std::cerr << "Could not open: " << filepath << std::endl;
            return false;
        }

        std::stringstream buffer;
        buffer << file.rdbuf();
        std::string content = buffer.str();

        // Parse shape
        size_t shape_pos = content.find("\"shape\"");
        if (shape_pos != std::string::npos) {
            size_t start = content.find('[', shape_pos);
            size_t end = content.find(']', start);
            std::string shape_str = content.substr(start + 1, end - start - 1);
            parseIntArray(shape_str, shape);
        }

        // Parse dtype
        size_t dtype_pos = content.find("\"dtype\"");
        if (dtype_pos != std::string::npos) {
            size_t start = content.find('"', dtype_pos + 7);
            size_t end = content.find('"', start + 1);
            dtype = content.substr(start + 1, end - start - 1);
        }

        // Parse data array
        size_t data_pos = content.find("\"data\"");
        if (data_pos != std::string::npos) {
            size_t start = content.find('[', data_pos);
            size_t end = content.rfind(']');
            // Handle nested arrays - find the actual data array
            size_t bracket_count = 0;
            for (size_t i = start; i <= end; ++i) {
                if (content[i] == '[') bracket_count++;
                if (content[i] == ']') bracket_count--;
                if (bracket_count == 0) {
                    end = i;
                    break;
                }
            }
            std::string data_str = content.substr(start + 1, end - start - 1);
            parseDoubleArray(data_str, data);
        }

        return !data.empty();
    }

    ArrayXr toArrayXr() const {
        ArrayXr arr(data.size());
        for (size_t i = 0; i < data.size(); ++i) {
            arr(i) = static_cast<Real>(data[i]);
        }
        return arr;
    }

    ArrayXXr toArrayXXr() const {
        if (shape.size() != 2) {
            return ArrayXXr();
        }
        ArrayXXr arr(shape[0], shape[1]);
        size_t idx = 0;
        for (int64_t i = 0; i < shape[0]; ++i) {
            for (int64_t j = 0; j < shape[1]; ++j) {
                arr(i, j) = static_cast<Real>(data[idx++]);
            }
        }
        return arr;
    }

private:
    void parseIntArray(const std::string& str, std::vector<int64_t>& arr) {
        arr.clear();
        std::string num;
        for (char c : str) {
            if (c >= '0' && c <= '9') {
                num += c;
            } else if (!num.empty()) {
                arr.push_back(std::stoll(num));
                num.clear();
            }
        }
        if (!num.empty()) {
            arr.push_back(std::stoll(num));
        }
    }

    void parseDoubleArray(const std::string& str, std::vector<double>& arr) {
        arr.clear();
        std::string num;
        bool in_num = false;
        for (char c : str) {
            if ((c >= '0' && c <= '9') || c == '.' || c == '-' || c == 'e' || c == 'E' || c == '+') {
                num += c;
                in_num = true;
            } else if (in_num && !num.empty()) {
                try {
                    arr.push_back(std::stod(num));
                } catch (...) {}
                num.clear();
                in_num = false;
            }
        }
        if (!num.empty()) {
            try {
                arr.push_back(std::stod(num));
            } catch (...) {}
        }
    }
};

} // namespace json_util

// ============================================================================
// Test Fixture
// ============================================================================

class CrossValidationTest : public ::testing::Test {
protected:
    static constexpr double DEFAULT_TOLERANCE = 1e-5;
    static constexpr double LOOSE_TOLERANCE = 1e-3;

    std::string dataDir;

    void SetUp() override {
        // Try to find the reference data directory
        std::vector<std::string> possible_paths = {
            "tests/crossval/reference_data",
            "../tests/crossval/reference_data",
            "../../tests/crossval/reference_data",
        };

        for (const auto& path : possible_paths) {
            std::ifstream test(path + "/convert_hz_to_mel_htk.json");
            if (test.good()) {
                dataDir = path;
                break;
            }
        }
    }

    bool loadArray(const std::string& name, json_util::ArrayData& arr) {
        std::string filepath = dataDir + "/" + name + ".json";
        return arr.load(filepath);
    }

    // Compare arrays with tolerance
    void expectArrayNear(const ArrayXr& actual, const ArrayXr& expected,
                         double tol = DEFAULT_TOLERANCE, const std::string& msg = "") {
        ASSERT_EQ(actual.size(), expected.size()) << msg << " size mismatch";
        for (Eigen::Index i = 0; i < actual.size(); ++i) {
            EXPECT_NEAR(actual(i), expected(i), tol)
                << msg << " at index " << i;
        }
    }

    void expectArrayNear(const ArrayXXr& actual, const ArrayXXr& expected,
                         double tol = DEFAULT_TOLERANCE, const std::string& msg = "") {
        ASSERT_EQ(actual.rows(), expected.rows()) << msg << " rows mismatch";
        ASSERT_EQ(actual.cols(), expected.cols()) << msg << " cols mismatch";
        for (Eigen::Index i = 0; i < actual.rows(); ++i) {
            for (Eigen::Index j = 0; j < actual.cols(); ++j) {
                EXPECT_NEAR(actual(i, j), expected(i, j), tol)
                    << msg << " at (" << i << ", " << j << ")";
            }
        }
    }

    // Compare with relative tolerance (for values that span orders of magnitude)
    void expectArrayRelNear(const ArrayXr& actual, const ArrayXr& expected,
                            double rel_tol = 1e-4, const std::string& msg = "") {
        ASSERT_EQ(actual.size(), expected.size()) << msg << " size mismatch";
        for (Eigen::Index i = 0; i < actual.size(); ++i) {
            double scale = std::max(std::abs(expected(i)), 1.0);
            EXPECT_NEAR(actual(i), expected(i), rel_tol * scale)
                << msg << " at index " << i;
        }
    }

    // Compare 2D arrays with relative tolerance
    void expectArrayRelNear2D(const ArrayXXr& actual, const ArrayXXr& expected,
                              double rel_tol = 1e-4, const std::string& msg = "") {
        ASSERT_EQ(actual.rows(), expected.rows()) << msg << " rows mismatch";
        ASSERT_EQ(actual.cols(), expected.cols()) << msg << " cols mismatch";
        for (Eigen::Index i = 0; i < actual.rows(); ++i) {
            for (Eigen::Index j = 0; j < actual.cols(); ++j) {
                double scale = std::max(std::abs(expected(i, j)), 1.0);
                EXPECT_NEAR(actual(i, j), expected(i, j), rel_tol * scale)
                    << msg << " at (" << i << ", " << j << ")";
            }
        }
    }

    // Compare event arrays with proximity matching (for onset/beat frames)
    // Checks that counts are similar and each detected event is near a reference event
    void expectEventsNear(const std::vector<Eigen::Index>& actual,
                          const ArrayXr& expected,
                          int proximity = 2,
                          double count_tolerance = 0.5,
                          const std::string& msg = "") {
        // Allow count to differ by count_tolerance fraction
        int expected_count = static_cast<int>(expected.size());
        int actual_count = static_cast<int>(actual.size());
        EXPECT_GT(actual_count, 0) << msg << " no events detected";
        double count_ratio = static_cast<double>(std::abs(actual_count - expected_count))
                           / std::max(expected_count, 1);
        EXPECT_LT(count_ratio, count_tolerance)
            << msg << " event count differs too much: "
            << actual_count << " vs " << expected_count;

        // Check each actual event is near some expected event
        int matched = 0;
        for (int i = 0; i < actual_count; ++i) {
            bool found = false;
            for (Eigen::Index j = 0; j < expected.size(); ++j) {
                if (std::abs(static_cast<double>(actual[i]) - expected(j)) <= proximity) {
                    found = true;
                    break;
                }
            }
            if (found) matched++;
        }
        double match_ratio = static_cast<double>(matched) / std::max(actual_count, 1);
        EXPECT_GT(match_ratio, 0.5) << msg << " too few events matched";
    }

    void expectEventsEqual(const std::vector<Eigen::Index>& actual,
                           const ArrayXr& expected,
                           const std::string& msg = "") {
        ASSERT_EQ(actual.size(), static_cast<size_t>(expected.size()))
            << msg << " event count mismatch";
        for (Eigen::Index i = 0; i < expected.size(); ++i) {
            EXPECT_EQ(actual[static_cast<size_t>(i)],
                      static_cast<Eigen::Index>(std::llround(expected(i))))
                << msg << " at event " << i;
        }
    }

    // Check reconstruction quality: ||W*H - S|| / ||S|| < tol
    void expectReconstructionQuality(const ArrayXXr& W, const ArrayXXr& H,
                                     const ArrayXXr& S, double tol = 0.1,
                                     const std::string& msg = "") {
        ArrayXXr recon = (W.matrix() * H.matrix()).array();
        ASSERT_EQ(recon.rows(), S.rows()) << msg << " reconstruction rows mismatch";
        ASSERT_EQ(recon.cols(), S.cols()) << msg << " reconstruction cols mismatch";
        double residual = (recon - S).matrix().norm();
        double original = S.matrix().norm();
        EXPECT_LT(residual / std::max(original, 1e-10), tol)
            << msg << " reconstruction quality: " << residual / original;
    }
};

// ============================================================================
// Convert Module Tests
// ============================================================================

TEST_F(CrossValidationTest, HzToMelHTK) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData ref;
    ASSERT_TRUE(loadArray("convert_hz_to_mel_htk", ref));

    ArrayXr hz(6);
    hz << 100, 200, 440, 1000, 4000, 8000;

    ArrayXr mel_cpp(6);
    for (int i = 0; i < 6; ++i) {
        mel_cpp(i) = hz_to_mel(hz(i), true);
    }

    expectArrayNear(mel_cpp, ref.toArrayXr(), DEFAULT_TOLERANCE, "hz_to_mel HTK");
}

