TEST_F(CrossValidationTest, MelToHzHTK) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData ref;
    ASSERT_TRUE(loadArray("convert_mel_to_hz_htk", ref));

    ArrayXr mel(6);
    mel << 100, 500, 1000, 1500, 2000, 2500;

    ArrayXr hz_cpp(6);
    for (int i = 0; i < 6; ++i) {
        hz_cpp(i) = mel_to_hz(mel(i), true);
    }

    // The Slaney input range (up to mel=2500) hits the exponential regime where
    // mel_to_hz output grows to ~1e77, so absolute tolerance is meaningless;
    // use relative tolerance that still catches anything beyond ~1 ULP drift
    // between platforms' libm exp().
    expectArrayRelNear(hz_cpp, ref.toArrayXr(), 1e-12, "mel_to_hz HTK");
}

