TEST_F(CrossValidationTest, MelFilterbank) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData ref;
    ASSERT_TRUE(loadArray("filters_mel_filterbank", ref));

    Real sr = 22050;
    int n_fft = 2048;
    int n_mels = 128;

    ArrayXXr mel_fb = filters::mel(sr, n_fft, n_mels);
    ArrayXXr expected = ref.toArrayXXr();

    ASSERT_EQ(mel_fb.rows(), expected.rows());
    ASSERT_EQ(mel_fb.cols(), expected.cols());

    // Use loose tolerance for filter banks
    expectArrayNear(mel_fb, expected, LOOSE_TOLERANCE, "mel filterbank");
}

