TEST_F(CrossValidationTest, StftMagnitude) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData signal_ref, mag_ref;
    if (!loadArray("spectrum_test_signal", signal_ref)) GTEST_SKIP();
    if (!loadArray("spectrum_stft_magnitude", mag_ref)) GTEST_SKIP();

    ArrayXr y = signal_ref.toArrayXr();
    ArrayXXc D = stft(y, 2048, 512);
    ArrayXXr mag_cpp = D.abs();
    ArrayXXr mag_py = mag_ref.toArrayXXr();

    ASSERT_EQ(mag_cpp.rows(), mag_py.rows());
    ASSERT_EQ(mag_cpp.cols(), mag_py.cols());

    expectArrayNear(mag_cpp, mag_py, LOOSE_TOLERANCE, "STFT magnitude");
}

