TEST_F(CrossValidationTest, MelToStft) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData mel_ref, result_ref;
    if (!loadArray("feature_mel_to_stft_input", mel_ref)) GTEST_SKIP();
    if (!loadArray("feature_mel_to_stft", result_ref)) GTEST_SKIP();

    ArrayXXr M = mel_ref.toArrayXXr();
    ArrayXXr result_cpp = feature::mel_to_stft(M);
    ArrayXXr result_py = result_ref.toArrayXXr();

    ASSERT_EQ(result_cpp.rows(), result_py.rows());
    ASSERT_EQ(result_cpp.cols(), result_py.cols());

    // NNLS is underdetermined (128 mel bins -> 1025 freq bins), so multiple valid
    // solutions exist. C++ fnnls produces sparser solutions than Python's L-BFGS-B.
    // Instead of comparing solutions directly, verify reconstruction quality:
    // check that mel_basis * X^2 ≈ M (mel_to_stft uses power=2 by default)
    Real sr = 22050;
    int n_fft = 2048;
    ArrayXXr mel_basis = filters::mel(sr, n_fft, static_cast<int>(M.rows()));

    ArrayXXr M_recon = (mel_basis.matrix() * (result_cpp * result_cpp).matrix()).array();
    Real max_val = M.maxCoeff();
    for (Eigen::Index i = 0; i < M.rows(); ++i) {
        for (Eigen::Index j = 0; j < M.cols(); ++j) {
            double tol = std::max(0.05 * std::abs(M(i, j)), 1e-6 * max_val);
            EXPECT_NEAR(M_recon(i, j), M(i, j), tol)
                << "mel_to_stft reconstruction at (" << i << ", " << j << ")";
        }
    }
}

