TEST_F(CrossValidationTest, TransitionLocal) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData ref;
    ASSERT_TRUE(loadArray("sequence_transition_local", ref));

    ArrayXXr trans_cpp = sequence::transition_local(4, 3);
    ArrayXXr expected = ref.toArrayXXr();

    ASSERT_EQ(trans_cpp.rows(), expected.rows());
    ASSERT_EQ(trans_cpp.cols(), expected.cols());

    // Verify structural properties of the transition matrix:
    // 1. All rows should sum to 1 (stochastic matrix)
    for (Eigen::Index i = 0; i < trans_cpp.rows(); ++i) {
        EXPECT_NEAR(trans_cpp.row(i).sum(), 1.0, 1e-10)
            << "transition_local row " << i << " does not sum to 1";
    }
    // 2. All entries should be non-negative
    EXPECT_GE(trans_cpp.minCoeff(), 0.0) << "transition_local has negative entries";
    // 3. Matrix should be banded (zero outside width)
    for (Eigen::Index i = 0; i < trans_cpp.rows(); ++i) {
        for (Eigen::Index j = 0; j < trans_cpp.cols(); ++j) {
            // Width=3 means transitions can go at most 1 step in each direction
            if (std::abs(i - j) > 1) {
                EXPECT_NEAR(trans_cpp(i, j), 0.0, 1e-10)
                    << "transition_local should be zero at (" << i << ", " << j << ")";
            }
        }
    }
}

TEST_F(CrossValidationTest, Viterbi) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData ref;
    ASSERT_TRUE(loadArray("sequence_viterbi_path", ref));

    // Reconstruct the Viterbi problem from generate_references.py
    ArrayXXr prob(2, 3);
    prob << 0.1, 0.4, 0.5,
            0.6, 0.3, 0.1;

    ArrayXXr transition(2, 2);
    transition << 0.7, 0.3,
                  0.4, 0.6;

    ArrayXr init(2);
    init << 0.6, 0.4;

    // Combine init with first observation
    ArrayXXr obs_prob = prob;
    obs_prob.col(0) *= init;

    std::vector<int> path_cpp = sequence::viterbi(obs_prob, transition);
    ArrayXr path_py = ref.toArrayXr();

    ASSERT_EQ(static_cast<int>(path_cpp.size()), static_cast<int>(path_py.size()));
    for (size_t i = 0; i < path_cpp.size(); ++i) {
        EXPECT_EQ(path_cpp[i], static_cast<int>(path_py(i))) << "viterbi at " << i;
    }
}

