TEST_F(CrossValidationTest, DtwPath) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData ref;
    ASSERT_TRUE(loadArray("sequence_dtw_path", ref));

    ArrayXXr X(1, 5);
    X << 1, 2, 3, 4, 5;
    ArrayXXr Y(1, 6);
    Y << 1, 2, 2, 3, 4, 5;

    auto [D_cpp, wp_cpp] = sequence::dtw_backtrack(X, Y);
    ArrayXXr wp_py = ref.toArrayXXr();

    ASSERT_EQ(static_cast<int>(wp_cpp.size()), static_cast<int>(wp_py.rows()));

    // C++ returns path start-to-end, Python returns end-to-start.
    // Check if paths match in either direction.
    bool forward_match = true, reverse_match = true;
    for (size_t i = 0; i < wp_cpp.size(); ++i) {
        size_t ri = wp_cpp.size() - 1 - i;
        if (wp_cpp[i].first != static_cast<int>(wp_py(i, 0)) ||
            wp_cpp[i].second != static_cast<int>(wp_py(i, 1)))
            forward_match = false;
        if (wp_cpp[i].first != static_cast<int>(wp_py(ri, 0)) ||
            wp_cpp[i].second != static_cast<int>(wp_py(ri, 1)))
            reverse_match = false;
    }
    EXPECT_TRUE(forward_match || reverse_match) << "DTW path doesn't match in either direction";
}

