// Pitch Estimation Tests
// ============================================================================

TEST_F(CrossValidationTest, PitchYin) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData signal_ref, yin_ref;
    if (!loadArray("pitch_test_signal", signal_ref)) GTEST_SKIP();
    if (!loadArray("pitch_yin_f0", yin_ref)) GTEST_SKIP();

    ArrayXr y = signal_ref.toArrayXr();
    ArrayXr f0_cpp = yin(y, 65.0, 2093.0, 22050);
    ArrayXr f0_py = yin_ref.toArrayXr();

    ASSERT_EQ(f0_cpp.size(), f0_py.size());

    // Compare mean voiced f0 (ignore unvoiced frames marked as 0)
    double sum_cpp = 0, sum_py = 0;
    int count_cpp = 0, count_py = 0;
    for (Eigen::Index i = 0; i < f0_cpp.size(); ++i) {
        if (f0_cpp(i) > 0) { sum_cpp += f0_cpp(i); count_cpp++; }
        if (f0_py(i) > 0) { sum_py += f0_py(i); count_py++; }
    }
    double mean_cpp = count_cpp > 0 ? sum_cpp / count_cpp : 0;
    double mean_py = count_py > 0 ? sum_py / count_py : 0;

    EXPECT_NEAR(mean_cpp, mean_py, 5.0) << "YIN mean f0 differs too much";
}

TEST_F(CrossValidationTest, PitchPyin) {
    if (dataDir.empty()) GTEST_SKIP() << "Reference data not found";

    json_util::ArrayData signal_ref, pyin_ref, voiced_ref;
    if (!loadArray("pitch_test_signal", signal_ref)) GTEST_SKIP();
    if (!loadArray("pitch_pyin_f0", pyin_ref)) GTEST_SKIP();
    if (!loadArray("pitch_pyin_voiced", voiced_ref)) GTEST_SKIP();

    ArrayXr y = signal_ref.toArrayXr();
    auto result = pyin(y, 65.0, 2093.0, 22050);
    ArrayXr f0_py = pyin_ref.toArrayXr();
    ArrayXr voiced_py = voiced_ref.toArrayXr();

    ASSERT_EQ(result.f0.size(), f0_py.size());

    // Compare mean voiced f0 (NaN/-1 = unvoiced)
    double sum_cpp = 0, sum_py = 0;
    int count_cpp = 0, count_py = 0;
    for (Eigen::Index i = 0; i < result.f0.size(); ++i) {
        if (!std::isnan(result.f0(i)) && result.f0(i) > 0) {
            sum_cpp += result.f0(i);
            count_cpp++;
        }
        if (f0_py(i) > 0) {  // -1 means unvoiced in our JSON
            sum_py += f0_py(i);
            count_py++;
        }
    }
    double mean_cpp = count_cpp > 0 ? sum_cpp / count_cpp : 0;
    double mean_py = count_py > 0 ? sum_py / count_py : 0;

    EXPECT_NEAR(mean_cpp, mean_py, 5.0) << "pYIN mean f0 differs too much";

    // Compare voiced frame count within 20%
    int voiced_cpp = 0, voiced_py_count = 0;
    for (Eigen::Index i = 0; i < result.voiced_flag.size(); ++i) {
        if (result.voiced_flag(i)) voiced_cpp++;
    }
    for (Eigen::Index i = 0; i < voiced_py.size(); ++i) {
        if (voiced_py(i) > 0.5) voiced_py_count++;
    }
    double count_ratio = static_cast<double>(std::abs(voiced_cpp - voiced_py_count))
                       / std::max(voiced_py_count, 1);
    EXPECT_LT(count_ratio, 0.2) << "pYIN voiced frame count: "
        << voiced_cpp << " vs " << voiced_py_count;
}

